const stats = $('DB: Get Order Stats').first().json;
const stuck = $('DB: Get Stuck Orders Detail').all();

const stuckPaid = parseInt(stats.stuck_paid || 0);
const abandoned = parseInt(stats.abandoned_created || 0);
const stuckProgress = parseInt(stats.stuck_in_progress || 0);
const justCompleted = parseInt(stats.just_completed || 0);
const recentRefunds = parseInt(stats.recent_refunds || 0);
const revenue = parseFloat(stats.revenue_30min || 0) / 100;

// Build alert message
let alerts = [];
let hasIssues = false;

if (stuckPaid > 0) {
  hasIssues = true;
  alerts.push(`🔴 *PAID зависших:* ${stuckPaid} заказов > 2ч`);
}
if (stuckProgress > 0) {
  hasIssues = true;
  alerts.push(`🟠 *IN_PROGRESS зависших:* ${stuckProgress} заказов > 4ч`);
}
if (abandoned > 5) {
  hasIssues = true;
  alerts.push(`🟡 *Брошенных CREATED:* ${abandoned} > 1ч`);
}
if (recentRefunds >= 3) {
  hasIssues = true;
  alerts.push(`⚠️ *Возвратов за 30мин:* ${recentRefunds} — проверить!`);
}

// Build stuck orders detail
let stuckDetail = '';
if (stuck.length > 0) {
  stuckDetail = '\n\n*Зависшие заказы:*\n';
  stuck.forEach(s => {
    const item = s.json;
    stuckDetail += `• #${item.id} | ${item.status} | ${item.hours_stuck}ч | €${(item.total_eur || 0).toFixed(2)} | ${item.product_title || 'Unknown'}\n`;
  });
}

// Pulse line (always send)
const pulse = `📡 *GG Pulse* | ${new Date().toLocaleTimeString('ru-RU', {timeZone: 'Europe/Moscow', hour: '2-digit', minute: '2-digit'})}\n\n` +
  `✅ Завершено за 30мин: ${justCompleted}\n` +
  `💰 Выручка за 30мин: €${revenue.toFixed(2)}\n` +
  `❌ Возвратов: ${recentRefunds}\n` +
  `🛒 Брошенных: ${abandoned}`;

let fullMessage = pulse;
if (hasIssues) {
  fullMessage = `🚨 *ВНИМАНИЕ! Проблемы на бирже*\n\n` + alerts.join('\n') + stuckDetail + '\n\n---\n' + pulse;
}

return [{ json: { message: fullMessage, hasIssues } }];
